class Solution:
    def numRollsToTarget(self, n, k, target):
        MOD = 10**9 + 7
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def rec(dice_left, need):
            if dice_left == 0:
                return 1 if need == 0 else 0
            if need < dice_left or need > dice_left * k:
                return 0
            total = 0
            for face in range(1, k + 1):
                total += rec(dice_left - 1, need - face)
            return total % MOD
        return rec(n, target) % MOD

