class Solution:
    def numRollsToTarget(self, n, k, target):
        MOD = 10**9 + 7
        ways = [0] * (target + 1)
        ways[0] = 1
        for _ in range(n):
            nxt = [0] * (target + 1)
            for s in range(target + 1):
                if ways[s] == 0:
                    continue
                for f in range(1, k + 1):
                    if s + f <= target:
                        nxt[s + f] = (nxt[s + f] + ways[s]) % MOD
            ways = nxt
        return ways[target] % MOD

