var numRollsToTarget = function(n, k, target) {
    const MOD = 1000000007n;
    let ways = new Array(target + 1).fill(0n);
    ways[0] = 1n;
    for (let d = 0; d < n; d++) {
        const nxt = new Array(target + 1).fill(0n);
        for (let s = 0; s <= target; s++) {
            if (ways[s] === 0n) continue;
            for (let f = 1; f <= k; f++) {
                if (s + f <= target) nxt[s + f] = (nxt[s + f] + ways[s]) % MOD;
            }
        }
        ways = nxt;
    }
    return Number(ways[target] % MOD);
};
